import { useEffect, useState } from "react";
import "./moviesstyle.css";
import bookmark from "../src/assets/bookmark.png";

function Movies() {
  const [allmovies, setAllMovies] = useState([]);
  const [favMovies, setFavMovies] = useState([]);

  useEffect(() => {
    async function getmovies() {
      // fetch pages 1..5 in parallel
      const pages = [1, 2, 3, 4, 5];

      const results = await Promise.all(
        pages.map(async (p) => {
          const res = await fetch(
            `https://api.themoviedb.org/3/movie/popular?api_key=438b5d80663af506dbe9658849a35777&language=en-US&page=${p}`
          );
          const json = await res.json();
          return json.results || [];
        })
      );

      setAllMovies(results.flat());
    }

    getmovies();
  }, []);

  async function favthemovie(movie) {
    // Build a clean object to send to backend
    const payload = {
      tmdbId: movie.id,
      title: movie.original_title,
      popularity: movie.popularity,
      vote: movie.vote_average,
      releaseDate: movie.release_date,
      img: `https://image.tmdb.org/t/p/w500${movie.backdrop_path}`,
    };

    await fetch("http://localhost:5000/addfavmovie", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({ allfavmoviedata: payload }),
    });

    // If your backend returns ALL favourites here, this becomes your single source of truth.
    const sessionget = await fetch("http://localhost:5000/receivefavmovie", {
      method: "GET",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
    });

    const jsonsessionget = await sessionget.json();

    // ✅ Best case: backend returns an array of fav movies
    // If it doesn’t, normalize it:
    const normalized = Array.isArray(jsonsessionget)
      ? jsonsessionget
      : Object.values(jsonsessionget);

    setFavMovies(normalized);
  }

  return (
    <>
      <div id="movies-shell">
        <div id="movies-header">
          <p id="movies-title">Popular Movies</p>
        </div>

        <div id="movies-row">
          {allmovies.map((item) => (
            <div className="movie-card" key={item.id}>
              <img
                className="movie-img"
                src={`https://image.tmdb.org/t/p/w500${item.backdrop_path}`}
                alt={item.original_title}
              />

              <div className="movie-title-row">
                <p className="movie-title">{item.original_title}</p>

                <img
                  onClick={() => favthemovie(item)}
                  className="movie-bookmark"
                  src={bookmark}
                  alt="bookmark"
                />
              </div>

              <p className="movie-meta">Popularity: {item.popularity}</p>
              <p className="movie-meta">Vote: {item.vote_average}</p>
              <p className="movie-meta">Release: {item.release_date}</p>
            </div>
          ))}
        </div>

        {/* ✅ FAV SECTION UNDER MOVIES */}
        <div id="fav-shell">
          <div id="fav-header">
            <p id="fav-title">Favourites</p>
            <p id="fav-subtitle">
              {favMovies.length ? `${favMovies.length} saved` : "No favourites yet"}
            </p>
          </div>

          <div id="fav-row">
            {favMovies.map((item, idx) => (
              <div className="movie-card fav-card" key={item.tmdbId ?? idx}>
                <img className="movie-img" src={item.img} alt={item.title} />

                <div className="movie-title-row">
                  <p className="movie-title">{item.title}</p>

                  <img
                    onClick={() => favthemovie(item)}
                    className="movie-bookmark"
                    src={bookmark}
                    alt="bookmark"
                  />
                </div>

                <p className="movie-meta">Popularity: {item.popularity}</p>
                <p className="movie-meta">Vote: {item.vote}</p>
                <p className="movie-meta">Release: {item.releaseDate}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </>
  );
}

export default Movies;
